package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorCountMinSurfaceTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void countMinDualExposesPrefixFactorSurfaceEstimate() {
		SketchBasedJoinEstimator estimator = countMinDualEstimatorWithSharedObjectRows();
		StatementPattern left = pattern("left", "urn:count-min:surface:left", "join");
		StatementPattern right = pattern("right", "urn:count-min:surface:right", "join");

		JoinFrequencyEstimate estimate = estimator.estimateCountMinJoinSurface(List.of(left), right, "join");

		assertCountMinSurfaceEstimate(estimate);
	}

	@Test
	void genericSketchSurfaceApiExposesPrefixFactorEstimate() {
		SketchBasedJoinEstimator estimator = countMinDualEstimatorWithSharedObjectRows();
		StatementPattern left = pattern("left", "urn:count-min:surface:left", "join");
		StatementPattern right = pattern("right", "urn:count-min:surface:right", "join");

		JoinFrequencyEstimate estimate = estimator.estimateSketchJoinSurface(List.of(left), right, "join");

		assertCountMinSurfaceEstimate(estimate);
	}

	@Test
	void countMinDualExposesPrefixOnlySurfaceEstimate() {
		SketchBasedJoinEstimator estimator = countMinDualEstimatorWithSharedObjectRows();
		StatementPattern left = pattern("left", "urn:count-min:surface:left", "join");
		StatementPattern right = pattern("right", "urn:count-min:surface:right", "join");

		JoinFrequencyEstimate estimate = estimator.estimateCountMinJoinSurface(List.of(left, right), "join");

		assertCountMinSurfaceEstimate(estimate);
	}

	@Test
	void genericSketchSurfaceApiExposesPrefixOnlyEstimate() {
		SketchBasedJoinEstimator estimator = countMinDualEstimatorWithSharedObjectRows();
		StatementPattern left = pattern("left", "urn:count-min:surface:left", "join");
		StatementPattern right = pattern("right", "urn:count-min:surface:right", "join");

		JoinFrequencyEstimate estimate = estimator.estimateSketchJoinSurface(List.of(left, right), "join");

		assertCountMinSurfaceEstimate(estimate);
	}

	@Test
	void countMinSurfaceEstimateRejectsDeleteSketches() {
		IRI leftPredicate = VF.createIRI("urn:count-min:surface:left");
		IRI rightPredicate = VF.createIRI("urn:count-min:surface:right");
		Value sharedObject = VF.createIRI("urn:count-min:surface:shared");
		Statement deletedLeft = st(VF.createIRI("urn:count-min:surface:deleted-left"), leftPredicate, sharedObject);
		StubSketchStatementSource store = new StubSketchStatementSource();
		store.add(deletedLeft);
		store.add(st(VF.createIRI("urn:count-min:surface:right-subject"), rightPredicate, sharedObject));
		SketchBasedJoinEstimator estimator = countMinDualEstimator(store);
		estimator.rebuild();

		estimator.deleteStatement(deletedLeft);
		estimator.debugFlushPendingIncremental();

		StatementPattern left = pattern("left", leftPredicate.stringValue(), "join");
		StatementPattern right = pattern("right", rightPredicate.stringValue(), "join");
		JoinFrequencyEstimate estimate = estimator.estimateCountMinJoinSurface(List.of(left), right, "join");

		assertTrue(estimate == null, "Count-Min evidence must not be used once delete side sketches are present");
	}

	private static void assertCountMinSurfaceEstimate(JoinFrequencyEstimate estimate) {
		assertNotNull(estimate);
		assertEquals("countmin-sketch-surface", estimate.source());
		assertTrue(estimate.upperBoundRows() >= 4.0d, "Count-Min should expose a conservative upper bound");
		assertEquals(estimate.upperBoundRows(), estimate.calibratedRows(), 0.0d);
		assertEquals(1.0d, estimate.calibrationFactor(), 0.0d);
		assertEquals(0.25d, estimate.confidence(), 0.0d);
	}

	private static SketchBasedJoinEstimator countMinDualEstimatorWithSharedObjectRows() {
		IRI leftPredicate = VF.createIRI("urn:count-min:surface:left");
		IRI rightPredicate = VF.createIRI("urn:count-min:surface:right");
		Value sharedObject = VF.createIRI("urn:count-min:surface:shared");
		StubSketchStatementSource store = new StubSketchStatementSource();
		store.add(st(VF.createIRI("urn:count-min:surface:left-1"), leftPredicate, sharedObject));
		store.add(st(VF.createIRI("urn:count-min:surface:left-2"), leftPredicate, sharedObject));
		store.add(st(VF.createIRI("urn:count-min:surface:right-1"), rightPredicate, sharedObject));
		store.add(st(VF.createIRI("urn:count-min:surface:right-2"), rightPredicate, sharedObject));
		SketchBasedJoinEstimator estimator = countMinDualEstimator(store);
		estimator.rebuild();
		return estimator;
	}

	private static SketchBasedJoinEstimator countMinDualEstimator(StubSketchStatementSource store) {
		return new SketchBasedJoinEstimator(store,
				SketchBasedJoinEstimator.Config.defaults()
						.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.COUNT_MIN_DUAL)
						.withThrottleEveryN(1)
						.withThrottleMillis(0));
	}

	private static StatementPattern pattern(String subjectName, String predicate, String objectName) {
		return new StatementPattern(Var.of(subjectName), Var.of("p", VF.createIRI(predicate)), Var.of(objectName));
	}

	private static Statement st(Resource subject, IRI predicate, Value object) {
		return VF.createStatement(subject, predicate, object);
	}
}
